import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Memory Model","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/memory.md","filePath":"archive/reference/memory.md"}'),o={name:"archive/reference/memory.md"};function i(l,e,r,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="memory-model" tabindex="-1">Memory Model <a class="header-anchor" href="#memory-model" aria-label="Permalink to &quot;Memory Model&quot;">​</a></h1><p>Vex provides a unique hybrid memory model that combines the deterministic safety of Rust&#39;s ownership system with the ease of use found in Go, all backed by the compile-time power of VUMM.</p><h2 id="_1-the-stack-and-the-heap" tabindex="-1">1. The Stack and The Heap <a class="header-anchor" href="#_1-the-stack-and-the-heap" aria-label="Permalink to &quot;1. The Stack and The Heap&quot;">​</a></h2><p>Like most systems languages, memory in Vex is divided into two primary regions:</p><h3 id="the-stack" tabindex="-1">The Stack <a class="header-anchor" href="#the-stack" aria-label="Permalink to &quot;The Stack&quot;">​</a></h3><ul><li><strong>Fast</strong>: Allocation is just moving a pointer.</li><li><strong>Deterministic</strong>: Automatically cleaned up when a function returns.</li><li><strong>Fixed Size</strong>: Values must have a known size at compile time.</li><li><strong>Contents</strong>: Functions arguments, local variables, standard structs, arrays.</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    let x = 42;          // Stack allocated</span></span>
<span class="line"><span>    let p = Point{1, 2}; // Stack allocated</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="the-heap" tabindex="-1">The Heap <a class="header-anchor" href="#the-heap" aria-label="Permalink to &quot;The Heap&quot;">​</a></h3><ul><li><strong>Dynamic</strong>: Used for data that grows or lives beyond the current scope.</li><li><strong>Slower</strong>: Requires a specialized allocator (<code>mimalloc</code>).</li><li><strong>Managed</strong>: Vex manages heap memory automatically via RAII (Resource Acquisition Is Initialization).</li><li><strong>Contents</strong>: <code>Box&lt;T&gt;</code>, <code>Vec&lt;T&gt;</code>, <code>HashMap</code>, <code>String</code>.</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    let b = Box.new(42); // Heap allocated int, pointer on stack</span></span>
<span class="line"><span>    let v = Vec.new();   // Heap buffer, pointer/len/cap on stack</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_2-ownership-system" tabindex="-1">2. Ownership System <a class="header-anchor" href="#_2-ownership-system" aria-label="Permalink to &quot;2. Ownership System&quot;">​</a></h2><p>Vex uses a strict ownership model to ensure memory safety without a Garbage Collector.</p><h3 id="the-three-rules" tabindex="-1">The Three Rules <a class="header-anchor" href="#the-three-rules" aria-label="Permalink to &quot;The Three Rules&quot;">​</a></h3><ol><li><strong>Each value in Vex has a variable that’s called its owner.</strong></li><li><strong>There can only be one owner at a time.</strong></li><li><strong>When the owner goes out of scope, the value is dropped.</strong></li></ol><h3 id="copy-vs-move" tabindex="-1">Copy vs Move <a class="header-anchor" href="#copy-vs-move" aria-label="Permalink to &quot;Copy vs Move&quot;">​</a></h3><ul><li><strong>Copy Types</strong>: Primitives (<code>i32</code>, <code>bool</code>, <code>f64</code>) are cheap to copy. Assigning them copies the bits.</li><li><strong>Move Types</strong>: Complex types (<code>structs</code>, <code>Vec</code>, <code>Box</code>) transfer ownership upon assignment.</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let a = 10;</span></span>
<span class="line"><span>let b = a; // Copy: Both &#39;a&#39; and &#39;b&#39; are usable (10)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let v1 = Vec.new();</span></span>
<span class="line"><span>let v2 = v1; // Move: Ownership transferred to &#39;v2&#39;. &#39;v1&#39; is now invalid.</span></span>
<span class="line"><span>// print(v1);</span><span> // Compile Error: Use of moved value</span></span></code></pre></div><hr><h2 id="_3-borrowing-references" tabindex="-1">3. Borrowing (References) <a class="header-anchor" href="#_3-borrowing-references" aria-label="Permalink to &quot;3. Borrowing (References)&quot;">​</a></h2><p>You can access data without taking ownership by &quot;borrowing&quot; it via references.</p><h3 id="reference-rules" tabindex="-1">Reference Rules <a class="header-anchor" href="#reference-rules" aria-label="Permalink to &quot;Reference Rules&quot;">​</a></h3><ul><li><strong>Immutable References (<code>&amp;T</code>)</strong>: You can have infinite immutable references. Read-only.</li><li><strong>Mutable References (<code>&amp;T!</code>)</strong>: You can have exactly one mutable reference. Exclusive access.</li><li><strong>Separation</strong>: You cannot have a mutable reference while immutable references exist.</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! x = 10;</span></span>
<span class="line"><span>let r1 = &amp;x;  // OK</span></span>
<span class="line"><span>let r2 = &amp;x;  // OK: Multiple readers</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// let m = &amp;x!;</span><span> // Error: Cannot borrow as mutable because &#39;x&#39; is already borrowed as immutable</span></span></code></pre></div><hr><h2 id="_4-vumm-vex-unified-memory-model" tabindex="-1">4. VUMM (Vex Unified Memory Model) <a class="header-anchor" href="#_4-vumm-vex-unified-memory-model" aria-label="Permalink to &quot;4. VUMM (Vex Unified Memory Model)&quot;">​</a></h2><p>For heap-allocated values wrapped in <code>Box&lt;T&gt;</code>, Vex uses a unique system called VUMM.</p><p>Unlike Rust (<code>Box</code> vs <code>Rc</code> vs <code>Arc</code>) or C++ (<code>unique_ptr</code> vs <code>shared_ptr</code>), Vex exposes a single <strong><code>Box&lt;T&gt;</code></strong> type. The compiler analyzes how you use the box and statically compiles it to the most efficient representation:</p><ol><li><strong>Unique</strong>: Zero overhead. Same as <code>unique_ptr</code>. Default.</li><li><strong>Shared</strong>: Compilation of <code>Box</code> changes to include a non-atomic refcount.</li><li><strong>Atomic</strong>: If the box crosses threads, it compiles to an atomic ref-counted pointer.</li></ol><p>See the <a href="./vumm">VUMM Reference</a> for low-level details.</p><hr><h2 id="_5-lifetimes" tabindex="-1">5. Lifetimes <a class="header-anchor" href="#_5-lifetimes" aria-label="Permalink to &quot;5. Lifetimes&quot;">​</a></h2><p>Lifetimes are the scope for which a reference is valid. Vex checks lifetimes at compile time to prevent:</p><ul><li><strong>Dangling Pointers</strong>: References to data that has been freed.</li><li><strong>Use After Free</strong>: Accessing memory after it&#39;s dropped.</li></ul><p>Currently, Vex uses an <strong>intra-procedural</strong> lifetime checking algorithm (Phase 4 of the Borrow Checker) which infers lifetimes automatically within functions. Explicit lifetime annotations (<code>&#39;a</code>) are not currently required or supported in user code, as the compiler handles most cases implicitly.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn return_ref(x: &amp;i32) : &amp;i32 {</span></span>
<span class="line"><span>    return x; // OK: Output lifetime tied to input</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/*</span></span>
<span class="line"><span>fn dangling() : &amp;i32 {</span></span>
<span class="line"><span>    let x = 10;</span></span>
<span class="line"><span>    return &amp;x; // Error: \`x\` does not live long enough</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>*/</span></span></code></pre></div>`,36)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
